using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var build = BinaryLog.ReadBuild(args[0]);

Console.WriteLine("=== BUILD RESULT: " + (build.Succeeded ? "SUCCESS" : "FAILED") + " ===\n");

// Collect all errors and warnings
var errors = new List<(string project, string code, string file, int line, int col, string message, string subcategory)>();
var warnings = new List<(string project, string code, string file, int line, int col, string message)>();

void Visit(BaseNode node, string currentProject = "")
{
    if (node is Project p)
        currentProject = p.Name;

    if (node is Error err)
    {
        errors.Add((currentProject, err.Code ?? "", err.File ?? "", err.LineNumber, err.ColumnNumber, err.Text ?? err.ToString(), err.Subcategory ?? ""));
    }
    else if (node is Warning warn)
    {
        warnings.Add((currentProject, warn.Code ?? "", warn.File ?? "", warn.LineNumber, warn.ColumnNumber, warn.Text ?? warn.ToString()));
    }

    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode bn)
                Visit(bn, currentProject);
        }
    }
}

Visit(build);

Console.WriteLine($"Total Errors: {errors.Count}");
Console.WriteLine($"Total Warnings: {warnings.Count}\n");

Console.WriteLine("=== ERRORS ===");
foreach (var (project, code, file, line, col, message, sub) in errors)
{
    Console.WriteLine($"[{project}] {file}({line},{col}): error {code}: {message}");
}

Console.WriteLine("\n=== WARNINGS ===");
foreach (var (project, code, file, line, col, message) in warnings)
{
    Console.WriteLine($"[{project}] {file}({line},{col}): warning {code}: {message}");
}

// Also look at project results
Console.WriteLine("\n=== PROJECT BUILD RESULTS ===");
void VisitProjects(BaseNode node)
{
    if (node is Project proj)
    {
        Console.WriteLine($"  {proj.Name} (Target: {proj.TargetFramework}) => Succeeded: {proj.Succeeded}");
    }
    if (node is TreeNode tn2)
    {
        foreach (var child in tn2.Children)
        {
            if (child is BaseNode bn)
                VisitProjects(bn);
        }
    }
}
VisitProjects(build);
