using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;

var build = BinaryLog.ReadBuild(args[0]);

// Check which projects had errors directly vs which just inherited failures
var projectErrors = new Dictionary<string, List<string>>();

void Visit(BaseNode node, string currentProject = "")
{
    if (node is Project p)
        currentProject = p.Name;

    if (node is Error err)
    {
        if (!projectErrors.ContainsKey(currentProject))
            projectErrors[currentProject] = new List<string>();
        projectErrors[currentProject].Add($"{err.File}({err.LineNumber},{err.ColumnNumber}): error {err.Code}: {err.Text}");
    }

    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode bn)
                Visit(bn, currentProject);
        }
    }
}

Visit(build);

Console.WriteLine("=== ERRORS BY PROJECT ===");
foreach (var kv in projectErrors)
{
    Console.WriteLine($"\nProject: {kv.Key}");
    foreach (var e in kv.Value)
        Console.WriteLine($"  {e}");
}

// Check if Api had any errors of its own
Console.WriteLine("\n=== Projects with direct errors ===");
foreach (var kv in projectErrors)
    Console.WriteLine($"  {kv.Key}: {kv.Value.Count} error(s)");

if (!projectErrors.ContainsKey("Api.csproj"))
    Console.WriteLine("  Api.csproj: 0 errors (cascading failure from dependency)");

// Also dump the source file content for UserService.cs if embedded
Console.WriteLine("\n=== Searching for source file content in the log ===");
void DumpMessages(BaseNode node, string proj = "", int depth = 0)
{
    if (node is Project p2)
        proj = p2.Name;
    if (node is CscTask csc)
    {
        Console.WriteLine($"\n  CSC Task in {proj}:");
        Console.WriteLine($"    CommandLine: {csc.CommandLineArguments}");
    }
    if (node is TreeNode tn2)
    {
        foreach (var child in tn2.Children)
        {
            if (child is BaseNode bn)
                DumpMessages(bn, proj, depth + 1);
        }
    }
}
DumpMessages(build);
